该脚本使用dubbo telnet方式（dubbo官网提供的dubbo python client目前只支持jsonrpc协议，目前环境不支持）,可以根据该脚本实现dev、test环境的接口自动化、压力测试，根据具体需求填补脚本即可。 #!/usr/bin/python # -*- coding:utf-8 -*- import json import telnetlib import unittest import time import re class Dubbo(telnetlib.Telnet): prompt = &#39;dubbo&gt;&#39; coding = &#39;utf-8&#39; def __init__(self, host=None, port=0): super().__init__(host, port) self.write(b&#39;
&#39;) def command(self, flag, str_=&quot;&quot;): data = self.read_until(flag.encode()) self.write(str_.encode() + b&quot;
&quot;) return data def invoke(self, service_name, method_name, args): command_str = &quot;invoke {0}.{1}({2})&quot;.format( service_name, method_name, args) self.command(Dubbo.prompt, command_str) data = self.command(Dubbo.prompt, &quot;&quot;) data = json.loads(data.decode( Dubbo.coding, errors=&#39;ignore&#39;).split(&#39;
&#39;)[0].strip()) return data class DcTest(unittest.TestCase): #setUp 用于设置初始化的部分，在测试用例执行前，这个方法中的函数将先被调用 # def setUp(self): &#39;&#39;&#39; 33: Dubbo(&#39;301.57.79.01&#39;, 27075) 44: Dubbo(&#39;106.12.59.915&#39;, 7075) dev: Dubbo(&#39;121.36.108.215&#39;, 6666) &#39;&#39;&#39; self.dubbo_conn = Dubbo(&#39;127.0.0.1&#39;, 6666) self.verificationErrors = [] # 脚本运行时，错误的信息将被打印到这个列表中# self.accept_next_alert = True # 是否继续接受下一个警告# # 更改司机状态 def test_update_driver_status(self): data = {&quot;class&quot;:&quot;com.caocao.dc.api.dto.input.DriverStatusDTO&quot;,&quot;driverNo&quot;:1003019,&quot;status&quot;:1} result = self.dubbo_conn.invoke( &quot;com.caocao.dc.api.app.DriverCenterApi&quot;, &quot;updateDriverStatus&quot;, data) print(result) time.sleep(2) # 司机开始服务 def test_start_service(self): data = {&quot;class&quot;: &quot;com.caocao.dc.api.dto.input.DriverStartServiceParam&quot;, &quot;driverNo&quot;: 1003019,&quot;lat&quot;: 30.206907552083333, &quot;lng&quot;: 120.22090521918403, &quot;orderLabel&quot;: 128, &quot;orderNo&quot;: 74602113541, &quot;bizType&quot;: 1} result = self.dubbo_conn.invoke( &quot;com.caocao.dc.api.app.response.DriverOrderResponseApi&quot;, &quot;startService&quot;, data) print(result) time.sleep(2) def tearDown(self): &#39;&#39;&#39; tearDown 方法在每个测试方法执行后调用，这个地方做所有清理工作，如退出浏览器等。 self.assertEqual([], self.verificationErrors) 是个难点， 对前面verificationErrors方法获得的列表进行比较；如查verificationErrors的列表不为空，输出列表中的报错信息。 &#39;&#39;&#39; self.assertEqual([], self.verificationErrors) class DriverSupportTest(unittest.TestCase): #setUp 用于设置初始化的部分，在测试用例执行前，这个方法中的函数将先被调用 # def setUp(self): &#39;&#39;&#39; 33: Dubbo(&#39;17.46.148.208&#39;, 7071) 44: Dubbo(&#39;19.22.19.25&#39;, 7075) &#39;&#39;&#39; self.dubbo_conn = Dubbo(&#39;97.92.238.218&#39;, 7071) self.verificationErrors = [] # 脚本运行时，错误的信息将被打印到这个列表中# self.accept_next_alert = True # 是否继续接受下一个警告# # 虚拟号AX预绑定 def test_pre_bind_phone(self): data = {&quot;class&quot;:&quot;com.caocao.driver.support.dto.phone.BindPhoneAxPreParam&quot;,&quot;customerPhone&quot;:&quot;4141241&quot;,&quot;orderNo&quot;:4141241,&quot;bizType&quot;:80,&quot;expireTime&quot;:1,&quot;areaCode&quot;:&quot;0571&quot;} result = self.dubbo_conn.invoke( &quot;com.caocao.driver.support.api.VirPhoneAxApi&quot;, &quot;preBindPhone&quot;, data) print(result) time.sleep(2) def tearDown(self): &#39;&#39;&#39; tearDown 方法在每个测试方法执行后调用，这个地方做所有清理工作，如退出浏览器等。 self.assertEqual([], self.verificationErrors) 是个难点， 对前面verificationErrors方法获得的列表进行比较；如查verificationErrors的列表不为空，输出列表中的报错信息。 &#39;&#39;&#39; self.assertEqual([], self.verificationErrors) &#39;&#39;&#39; driver-order &#39;&#39;&#39; class DriverOrderTest(unittest.TestCase): #setUp 用于设置初始化的部分，在测试用例执行前，这个方法中的函数将先被调用 # def setUp(self): &#39;&#39;&#39; 33: Dubbo(&#39;101.159.59.142&#39;, 7071) 44: Dubbo(&#39;106.2.9.25&#39;, 7071) &#39;&#39;&#39; self.dubbo_conn = Dubbo(&#39;111.32.49.515&#39;, 7071) self.verificationErrors = [] # 脚本运行时，错误的信息将被打印到这个列表中# self.accept_next_alert = True # 是否继续接受下一个警告# # 订单流程校验 def test_check_serve_flow(self): data = {&quot;class&quot;: &quot;com.caocao.driver.order.param.ServeFlowCheckParam&quot;, &quot;bizType&quot;: 1, &quot;cityCode&quot;: &quot;0571&quot;, &quot;driverNo&quot;: 3500035951, &quot;driverType&quot;: 1, &quot;orderLabel&quot;: 0, &quot;orderNo&quot;: 8361805001163, &quot;orderType&quot;: 1, &quot;serveFlow&quot;: 1} result = self.dubbo_conn.invoke( &quot;com.caocao.driver.order.api.DriverServeActionSupportApi&quot;, &quot;checkServeFlow&quot;, data) print(result) time.sleep(2) # 司机开始服务订单(实时单确认接单/预约单开始服务) def test_start_service(self): print(self.dubbo_conn) def tearDown(self): &#39;&#39;&#39; tearDown 方法在每个测试方法执行后调用，这个地方做所有清理工作，如退出浏览器等。 self.assertEqual([], self.verificationErrors) 是个难点， 对前面verificationErrors方法获得的列表进行比较；如查verificationErrors的列表不为空，输出列表中的报错信息。 &#39;&#39;&#39; self.assertEqual([], self.verificationErrors) &#39;&#39;&#39; local &#39;&#39;&#39; class LocalTest(unittest.TestCase): #setUp 用于设置初始化的部分，在测试用例执行前，这个方法中的函数将先被调用 # def setUp(self): &#39;&#39;&#39; local1: Dubbo(&#39;127.0.0.1&#39;, 20880) &#39;&#39;&#39; self.dubbo_conn = Dubbo(&#39;127.0.0.1&#39;, 20880) self.verificationErrors = [] # 脚本运行时，错误的信息将被打印到这个列表中# self.accept_next_alert = True # 是否继续接受下一个警告# # 测试sayHello def test_say_hello(self): for x in range(0,1): data = {&quot;class&quot;:&quot;com.alibaba.dubbo.demo.BeanParam&quot;,&quot;name&quot;:&quot;lios&quot;,&quot;age&quot;:25+x} result = self.dubbo_conn.invoke( &quot;com.alibaba.dubbo.demo.DemoService&quot;, &quot;hello&quot;, data) print(result) pass time.sleep(2) def test_2(self): print(self.dubbo_conn) def tearDown(self): &#39;&#39;&#39; tearDown 方法在每个测试方法执行后调用，这个地方做所有清理工作，如退出浏览器等。 self.assertEqual([], self.verificationErrors) 是个难点， 对前面verificationErrors方法获得的列表进行比较；如查verificationErrors的列表不为空，输出列表中的报错信息。 &#39;&#39;&#39; self.assertEqual([], self.verificationErrors) &#39;&#39;&#39; dc suite &#39;&#39;&#39; def dc_suite(): suite = unittest.TestSuite() suite.addTest(DcTest(&quot;test_update_driver_status&quot;)) suite.addTest(DcTest(&quot;test_start_service&quot;)) return suite pass &#39;&#39;&#39; driver-support suite &#39;&#39;&#39; def driver_support_suite(): suite = unittest.TestSuite() suite.addTest(DriverSupportTest(&quot;test_pre_bind_phone&quot;)) return suite pass &#39;&#39;&#39; driver-order suite &#39;&#39;&#39; def driver_order_suite(): suite = unittest.TestSuite() suite.addTest(DriverOrderTest(&quot;test_check_serve_flow&quot;)) suite.addTest(DriverOrderTest(&quot;test_start_service&quot;)) return suite pass &#39;&#39;&#39; local suite &#39;&#39;&#39; def local_suite(): suite = unittest.TestSuite() suite.addTest(LocalTest(&quot;test_say_hello&quot;)) return suite pass if __name__ == &quot;__main__&quot;: ## 指定suite套件 unittest.main(defaultTest=&#39;dc_suite&#39;)

为了埋点实时监控业务,简单的实现了钉钉机器人报警,钉钉开发官方文档点击 public interface AlarmService { Response&lt;Boolean&gt; orderSuccessAlarm(CompanyAppIdEnum companyAppIdEnum, String orderNo, OrderStatusEnum orderStatusEnum); Response&lt;Boolean&gt; orderFilterAlarm(CompanyAppIdEnum companyAppIdEnum,Long userId); } public class AlarmServcieImpl implements AlarmService { @Autowired RedisClient RedisClient; @Autowired ConfigUtil configUtil; private static final Log logger = LogFactory.getLog(AlarmServcieImpl.class); private static final Long expireTime = 24 * 60 * 60L; //创建机器人可获取 private static final String requestUrl = &quot;https://oapi.dingtalk.com/robot/send?access_token=xxxx&quot;; @Override public Response&lt;Boolean&gt; orderSuccessAlarm(CompanyAppIdEnum companyAppIdEnum, String orderNo, OrderStatusEnum orderStatusEnum) { try { if (configUtil.isServerTest()) { return new Response&lt;&gt;(Boolean.FALSE); } String count = RedisClient.getString(SystemConstants.ORDER_STATUS_ALARM_ROBOT, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); if (Objects.isNull(count)) { RedisClient.setString(SystemConstants.ORDER_STATUS_ALARM_ROBOT, &quot;0&quot;, expireTime, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); } dispatcher(companyAppIdEnum, Number.getNumber(Long.valueOf(RedisClient.getString(SystemConstants.ORDER_STATUS_ALARM_ROBOT, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())))), AlarmTypeEnum.ORDER_ALARM); RedisClient.incrBy(SystemConstants.ORDER_STATUS_ALARM_ROBOT, 1L, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); } catch (Exception e) { e.printStackTrace(); logger.error(e.getMessage(), e); } return new Response&lt;&gt;(Boolean.TRUE); } @Override public Response&lt;Boolean&gt; orderFilterAlarm(CompanyAppIdEnum companyAppIdEnum,Long userId) { try { if (configUtil.isServerTest()) { return new Response&lt;&gt;(Boolean.FALSE); } String count = RedisClient.getString(SystemConstants.ORDER_FILTER_USER_ALARM_ROBOT, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); if (Objects.isNull(count)) { RedisClient.setString(SystemConstants.ORDER_FILTER_USER_ALARM_ROBOT, &quot;0&quot;, expireTime, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); } dispatcher(companyAppIdEnum, Number.getNumber(Long.valueOf(RedisClient.getString(SystemConstants.ORDER_STATUS_ALARM_ROBOT, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())))), AlarmTypeEnum.ORDER_USER_FILTER); RedisClient.incrBy(SystemConstants.ORDER_STATUS_ALARM_ROBOT, 1L, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); } catch (Exception e) { e.printStackTrace(); logger.error(e.getMessage(), e); } return new Response&lt;&gt;(Boolean.TRUE); } protected void dispatcher(CompanyAppIdEnum companyAppIdEnum, Number number, AlarmTypeEnum alarmTypeEnum) { Arrays.asList(Number.values()).forEach( p -&gt; { if (p.equals(number) &amp;&amp; !Number.INIT_NUMBER.equals(number)) { try { sendNotice(companyAppIdEnum, number, alarmTypeEnum); } catch (IOException e) { e.printStackTrace(); logger.error(e.getMessage(), e); } return; } } ); } public static void main(String[] args) throws IOException { sendNotice(CompanyAppIdEnum.WAN_KA, Number.PRELIMINARY_WARNING, AlarmTypeEnum.ORDER_ALARM); } private static void sendNotice(CompanyAppIdEnum companyAppIdEnum, Number number, AlarmTypeEnum alarmTypeEnum) throws IOException { HttpClient httpclient = HttpClients.createDefault(); HttpPost httppost = new HttpPost(requestUrl); httppost.addHeader(&quot;Content-Type&quot;, &quot;application/json; charset=utf-8&quot;); String textMsg = getNotice(number, companyAppIdEnum, alarmTypeEnum); StringEntity se = new StringEntity(textMsg, &quot;utf-8&quot;); httppost.setEntity(se); HttpResponse response = httpclient.execute(httppost); if (response.getStatusLine().getStatusCode() == HttpStatus.SC_OK) { String result = EntityUtils.toString(response.getEntity(), &quot;utf-8&quot;); logger.info(&quot;报警已经成功发送,机构为:{},响应消息为:{}&quot;, companyAppIdEnum.getDesc(), result); } } private static String getNotice(Number number, CompanyAppIdEnum companyAppIdEnum, AlarmTypeEnum alarmTypeEnum) { switch (alarmTypeEnum) { case ORDER_ALARM: return &quot;{
&quot; + &quot; \&quot;msgtype\&quot;: \&quot;markdown\&quot;,
&quot; + &quot; \&quot;markdown\&quot;: {\&quot;title\&quot;:\&quot;推单失败报警\&quot;,
&quot; + &quot;\&quot;text\&quot;:\&quot;#### 推单失败报警 \n &quot; + companyAppIdEnum.getDesc() + &quot;推单失败已超过&quot; + number.getCount() + &quot;单&quot; + &quot;\n &gt; ![screenshot](https://note.youdao.com/yws/api/personal/file/WEB77f35c865dbd286c3baed15670e8892f?method=download&amp;shareKey=dfdd0302d114373146480ae3d4330af1)\n &gt; ######&quot; + new Date() + &quot;发布 [警告]() \&quot;
&quot; + &quot; },
&quot; + &quot; \&quot;at\&quot;: {
&quot; + &quot; \&quot;atMobiles\&quot;: [
&quot; + &quot; \&quot;15168426462\&quot;&quot; + &quot; ], 
&quot; + &quot; \&quot;isAtAll\&quot;: false
&quot; + &quot; }
&quot; + &quot; }&quot;; case ORDER_USER_FILTER: return &quot;{
&quot; + &quot; \&quot;msgtype\&quot;: \&quot;markdown\&quot;,
&quot; + &quot; \&quot;markdown\&quot;: {\&quot;title\&quot;:\&quot;机构过滤报警\&quot;,
&quot; + &quot;\&quot;text\&quot;:\&quot;#### 机构过滤报警 \n &quot; + companyAppIdEnum.getDesc() + &quot;过滤失败已超过&quot; + number.getCount() + &quot;单&quot; + &quot;\n &gt; ![screenshot](https://note.youdao.com/yws/api/personal/file/WEB77f35c865dbd286c3baed15670e8892f?method=download&amp;shareKey=dfdd0302d114373146480ae3d4330af1)\n &gt; ######&quot; + new Date() + &quot;发布 [警告]() \&quot;
&quot; + &quot; },
&quot; + &quot; \&quot;at\&quot;: {
&quot; + &quot; \&quot;atMobiles\&quot;: [
&quot; + &quot; \&quot;15168426462\&quot;&quot; + &quot; ], 
&quot; + &quot; \&quot;isAtAll\&quot;: false
&quot; + &quot; }
&quot; + &quot; }&quot;; default: break; } return &quot;&quot;; } public enum Number { INIT_NUMBER(0L, &quot;初始&quot;), PRELIMINARY_WARNING(50L, &quot;初步警告&quot;), PRELIMINARY_WARNING_PLUS(55L, &quot;初步警告&quot;), INTERMEDIATE_WARNING(100L, &quot;中级警告&quot;), INTERMEDIATE_WARNING_PLUS(105L, &quot;中级警告&quot;), INTERMEDIATE_WARNING_PLUS_PLUS(200L, &quot;中级++警告&quot;), INTERMEDIATE_WARNING_PLUS_PLUS_PLUS(205L, &quot;中级++警告&quot;), SERIOUS_WARNING(300L, &quot;严重警告&quot;), SERIOUS_WARNING_PLUS(305L, &quot;严重警告&quot;), SERIOUS_WARNING_PLUS_PLUS(350L, &quot;严重警告&quot;), SERIOUS_WARNING_PLUS_PLUS_PLUS(400L, &quot;严重警告&quot;), SERIOUS_WARNING_PLUS_PLUS_PLUS_PLUS(500L, &quot;严重警告&quot;); private Long count; private String desc; Number(Long count, String desc) { this.count = count; this.desc = desc; } public Long getCount() { return count; } public Number setCount(Long count) { this.count = count; return this; } public String getDesc() { return desc; } public Number setDesc(String desc) { this.desc = desc; return this; } public static Number getNumber(Long count) { Number[] number = {INIT_NUMBER}; Arrays.asList(Number.values()).forEach( p -&gt; { if (p.getCount().equals(count)) { number[0] = p; return; } } ); return number[0]; } } public enum AlarmTypeEnum { ORDER_ALARM, ORDER_USER_FILTER; } } 按照钉钉的文档来开发,创建机器人后,即可获取Webhook地址,整个过程还是很简单的,以上只是提供了一个思路.
